// modules/tasks/module.contract.ts
import { defineContract } from 'aether';

export default defineContract({
  name: 'tasks',
  description: 'Handles task creation, retrieval, and management utilities.',

  dependencies: { modules: ['auth'] },

  exposes: {
    routes: [
      { method: 'POST', path: '/tasks/create', auth: true },
    ],
    functions: ['createTask'],
    types: ['Task', 'TaskError'],
  },

  sideEffects: [
    'writes to: tasks table',
  ],

  invariants: [
    'A task must always be bound to exactly one team',
  ],
});

// modules/tasks/lib/queries.ts
import { query } from '../lib/db';
import { Task, TaskError } from '../lib/types';

export async function createTask(title: string, description: string, assigneeId: number): Promise<Result<Task, TaskError>> {
  try {
    const result = await query<Task>('INSERT INTO tasks (title, description, assignee_id) VALUES ($1, $2, $3) RETURNING *', [title, description, assigneeId]);
    return ok(result.rows[0]);
  } catch (error) {
    return err({ code: 'TASK_CREATE_ERROR', message: 'Failed to create task' });
  }
}

// modules/tasks/routes/create-task.ts
import { requireUser } from '../lib/auth';
import { parseBody, Result, ok, err } from '../lib/result';
import { TaskError } from '../lib/types';
import { createTask } from '../lib/queries';

export async function createTaskHandler(req: Request): Promise<Response> {
  const user = await requireUser(req);
  if (!user) return err({ code: 'UNAUTHORIZED', message: 'Unauthorized' });

  const body = parseBody<{ title: string, description: string, assigneeId: number }>(req.body);
  if (body.isErr()) return body;

  const { title, description, assigneeId } = body.value;
  if (!assigneeId) return err({ code: 'INVALID_INPUT', message: 'Assignee ID is required' });

  const result = await createTask(title, description, assigneeId);
  if (result.isErr()) return err(result.error);

  return ok({ status: 201, body: result.value });
}

// modules/tasks/lib/types.ts
import { Result } from '../lib/result';

export interface Task {
  id: number;
  title: string;
  description: string;
  assignee_id: number;
}

export interface TaskError {
  code: string;
  message: string;
}

// lib/db.ts
import { Pool, Client } from 'pg';
import { query as pgQuery } from 'pg';

const pool = new Pool({
  user: 'your_user',
  host: 'localhost',
  database: 'your_database',
  password: 'your_password',
  port: 5432,
});

export async function query<T>(text: string, params?: any[]): Promise<Result<T[], Error>> {
  try {
    const client = await pool.connect();
    const result = await client.query(text, params);
    client.release();
    return ok(result.rows as T[]);
  } catch (error) {
    return err(error);
  }
}

export async function transaction<T>(fn: (client: Client) => Promise<Result<T[], Error>>): Promise<Result<T[], Error>> {
  try {
    const client = await pool.connect();
    await client.query('BEGIN');
    const result = await fn(client);
    if (result.isOk()) {
      await client.query('COMMIT');
    } else {
      await client.query('ROLLBACK');
    }
    client.release();
    return result;
  } catch (error) {
    return err(error);
  }
}

// lib/auth.ts
import { requireUser as authRequireUser } from '../modules/auth/lib/queries';

export async function requireUser(req: Request): Promise<User | null> {
  const token = req.headers.authorization?.split(' ')[1];
  if (!token) return null;
  return await authRequireUser(token);
}

export async function getSession(req: Request): Promise<Session | null> {
  const user = await requireUser(req);
  if (!user) return null;
  // Implement session retrieval logic here
}

// lib/result.ts
export type Result<T, E> = Ok<T> | Err<E>;

interface Ok<T> {
  readonly isOk: true;
  readonly value: T;
}

interface Err<E> {
  readonly isOk: false;
  readonly error: E;
}

export function ok<T>(value: T): Ok<T> {
  return { isOk: true, value };
}

export function err<E>(error: E): Err<E> {
  return { isOk: false, error };
}

// lib/types.ts
export interface User {
  id: number;
  username: string;
  email: string;
}

export interface Session {
  id: number;
  user_id: number;
  token: string;
  expires_at: Date;
}

